fix_patch:
diff --git c/include/simdjson/dom/element-inl.h i/include/simdjson/dom/element-inl.h
index 1f071da608..6d2a80f2c4 100644
--- c/include/simdjson/dom/element-inl.h
+++ i/include/simdjson/dom/element-inl.h
@@ -383,8 +383,8 @@ inline simdjson_result<element> element::at_pointer(std::string_view json_pointe
     case internal::tape_type::START_ARRAY:
       return array(tape).at_pointer(json_pointer);
     default: {
-      if(!json_pointer.empty()) { // a non-empty string is invalid on an atom
-        return INVALID_JSON_POINTER;
+      if(!json_pointer.empty()) { // a non-empty JSON pointer on an atom cannot be resolved
+        return json_pointer[0] == '/' ? NO_SUCH_FIELD : INVALID_JSON_POINTER;
       }
       // an empty string means that we return the current node
       dom::element copy(*this);
diff --git c/include/simdjson/generic/ondemand/document-inl.h i/include/simdjson/generic/ondemand/document-inl.h
index 70072c42b1..1938d6e2ea 100644
--- c/include/simdjson/generic/ondemand/document-inl.h
+++ i/include/simdjson/generic/ondemand/document-inl.h
@@ -312,7 +312,7 @@ simdjson_inline simdjson_result<value> document::at_pointer(std::string_view jso
     case json_type::object:
       return (*this).get_object().at_pointer(json_pointer);
     default:
-      return INVALID_JSON_POINTER;
+      return json_pointer[0] == '/' ? NO_SUCH_FIELD : INVALID_JSON_POINTER;
   }
 }

